function cmsUrl(e){if(window.ElementoI18n?.assetUrl)return window.ElementoI18n.assetUrl(e);return`${window.ElementoI18n?window.ElementoI18n.getCmsBasePath():""}${e}`}function resolveMember(e){const n=window.ElementoI18n?window.ElementoI18n.getPageLocale():"en";return window.ElementoI18n?window.ElementoI18n.resolveCmsEntry(e,n):e}function loadTeam(){fetch(cmsUrl("CMS/team.json")).then(e=>{if(!e.ok)throw new Error(`HTTP error! status: ${e.status}`);return e.json()}).then(e=>{const n=document.getElementById("team-grid");if(!n)return;const t=e.map(e=>{const n=resolveMember(e),t=n.division?`division-${n.division}`:"division-default",o=n.photo||"assets/img/team/placeholder.png",s=window.ElementoI18n?.assetUrl?window.ElementoI18n.assetUrl(o):cmsUrl(o),a=window.ElementoI18n?.assetUrl?window.ElementoI18n.assetUrl("assets/img/team/placeholder.png"):cmsUrl("assets/img/team/placeholder.png");return`\n        <div class="team-member ${t}">\n          <div class="team-photo-container">\n            <div class="team-member-glow ${t}-glow"></div>\n            <img src="${s}" alt="${n.name}" class="team-photo" onerror="this.src='${a}'" />\n          </div>\n          <h4>${n.name}</h4>\n          <p class="team-role">${n.role}</p>\n          ${n.highlight?`<p class="team-highlight"><em>${n.highlight}</em></p>`:""}\n          <p class="team-bio">${n.bio}</p>\n          <div class="team-links">\n            ${(n.links||[]).map(e=>`<a href="${e.url}" target="_blank" class="btn btn-link">${e.type}</a>`).join("")}\n          </div>\n        </div>\n      `}).join("");n.innerHTML=t;n.querySelectorAll(".team-member.fade-in").forEach((e,n)=>{setTimeout(()=>e.classList.add("visible"),150*n)})}).catch(e=>{console.error("Error loading team data:",e)})}"loading"===document.readyState?document.addEventListener("DOMContentLoaded",loadTeam):loadTeam();